const errorResp = $('Fetch Recent Errors').first().json;
const lastCheckRaw = $('Fetch Last Check').first().json;

const executions = errorResp?.data || [];
if (!executions.length) {
  return [{ json: { hasNewErrors: false, errorCount: 0, criticalCount: 0, errors: [], lastErrorId: null } }];
}

// Get last check timestamp for dedup
const lastChecks = Array.isArray(lastCheckRaw) ? lastCheckRaw : (lastCheckRaw?.checked_at ? [lastCheckRaw] : []);
const lastCheckTime = lastChecks.length ? new Date(lastChecks[0].checked_at) : new Date(Date.now() - 5 * 60 * 1000);
const lastErrorId = lastChecks.length ? lastChecks[0].last_error_id : null;

// Filter to only new errors since last check
const newErrors = executions.filter(exec => {
  const finishedAt = exec.stoppedAt || exec.startedAt;
  if (!finishedAt) return false;
  if (new Date(finishedAt) <= lastCheckTime) return false;
  if (lastErrorId && exec.id === lastErrorId) return false;
  return true;
});

if (!newErrors.length) {
  return [{ json: { hasNewErrors: false, errorCount: 0, criticalCount: 0, errors: [], lastErrorId: executions[0]?.id || null } }];
}

// Infrastructure workflows = CRITICAL
const criticalWorkflows = ['TG-01', 'TG-05', 'TG-94', 'TG-95'];
const warningWorkflows = ['TG-09', 'TG-07', 'TG-126', 'TG-127', 'TG-128'];

// Count errors per workflow for escalation
const errorCounts = {};
for (const exec of executions) {
  const wfName = exec.workflowData?.name || '';
  const finishedAt = exec.stoppedAt || exec.startedAt;
  const oneHourAgo = Date.now() - 60 * 60 * 1000;
  if (finishedAt && new Date(finishedAt).getTime() > oneHourAgo) {
    errorCounts[wfName] = (errorCounts[wfName] || 0) + 1;
  }
}

const errors = newErrors.map(exec => {
  const wfName = exec.workflowData?.name || exec.workflowId || 'Unknown';
  const errorMsg = exec.data?.resultData?.error?.message || 'Execution failed';
  const timestamp = exec.stoppedAt || exec.startedAt;
  const hourlyCount = errorCounts[wfName] || 1;

  // Determine base severity
  let severity = 'INFO';
  if (criticalWorkflows.some(cw => wfName.includes(cw))) {
    severity = 'CRITICAL';
  } else if (warningWorkflows.some(ww => wfName.includes(ww))) {
    severity = 'WARNING';
  }

  // Escalate if 3+ errors in 1 hour for same workflow
  if (hourlyCount >= 3) {
    if (severity === 'INFO') severity = 'WARNING';
    else if (severity === 'WARNING') severity = 'CRITICAL';
  }

  return {
    workflowName: wfName,
    workflowId: exec.workflowId || '',
    errorMessage: errorMsg,
    timestamp,
    executionId: exec.id,
    severity,
    hourlyCount
  };
});

const criticalCount = errors.filter(e => e.severity === 'CRITICAL').length;

return [{ json: {
  hasNewErrors: true,
  errorCount: errors.length,
  criticalCount,
  errors,
  lastErrorId: executions[0]?.id || null
} }];

const { errors, errorCount, criticalCount } = $json;

// Split into critical and non-critical
const criticalErrors = errors.filter(e => e.severity === 'CRITICAL');
const otherErrors = errors.filter(e => e.severity !== 'CRITICAL');

const formatError = (e) => {
  const time = new Date(e.timestamp).toLocaleString('en-US', { timeZone: 'America/Chicago', hour: 'numeric', minute: '2-digit', hour12: true });
  return `Workflow: ${e.workflowName}\nError: ${e.errorMessage}\nCount: ${e.hourlyCount} in last hour\nTime: ${time}\nView: https://tgyardcare.app.n8n.cloud/workflow/${e.workflowId}/executions`;
};

const results = [];

if (criticalErrors.length) {
  const critMsg = [
    `\ud83d\udea8\ud83d\udea8\ud83d\udea8 CRITICAL SYSTEM ALERT`,
    ``,
    `${criticalErrors.length} critical error(s) detected`,
    `LEADS MAY BE DROPPING - check immediately`,
    ``,
    criticalErrors.map(formatError).join('\n\n---\n\n')
  ].join('\n');
  results.push({ json: { severity: 'CRITICAL', alert_message: critMsg, errors: criticalErrors } });
}

if (otherErrors.length) {
  const sevEmoji = otherErrors.some(e => e.severity === 'WARNING') ? '\u26a0\ufe0f' : '\u2139\ufe0f';
  const otherMsg = [
    `${sevEmoji} SYSTEM ALERT`,
    ``,
    `${otherErrors.length} workflow error(s) detected`,
    ``,
    otherErrors.map(formatError).join('\n\n---\n\n')
  ].join('\n');
  results.push({ json: { severity: 'OTHER', alert_message: otherMsg, errors: otherErrors } });
}

return results;

